def update_course(course_id, title, description):
    db = get_db()
    db.execute(
        'UPDATE courses SET title = ?, description = ? WHERE course_id = ?',
        (title, description, course_id),
    )
    db.commit()
    return get_course_by_id(course_id)


def delete_course(course_id):
